// VertexLexerInit initializes any static state used to implement VertexLexer. By default the
// static state used to implement the lexer is lazily initialized during the first call to
// NewVertexLexer(). You can call this function if you wish to initialize the static state ahead
// of time.
func VertexLexerInit() {
	staticData := &VertexLexerLexerStaticData
	staticData.once.Do(vertexlexerLexerInit)
}

// NewVertexLexer produces a new lexer instance for the optional input antlr.CharStream.
func NewVertexLexer(input antlr.CharStream) *VertexLexer {
	VertexLexerInit()
	l := new(VertexLexer)
	l.BaseLexer = antlr.NewBaseLexer(input)
	staticData := &VertexLexerLexerStaticData
	l.Interpreter = antlr.NewLexerATNSimulator(l, staticData.atn, staticData.decisionToDFA, staticData.PredictionContextCache)
	l.channelNames = staticData.ChannelNames
	l.modeNames = staticData.ModeNames
	l.RuleNames = staticData.RuleNames
	l.LiteralNames = staticData.LiteralNames
	l.SymbolicNames = staticData.SymbolicNames
	l.GrammarFileName = "VertexLexer.g4"
	// TODO: l.EOF = antlr.TokenEOF

	return l
}

